export const name = "repo";
export const version = "0.1.0";
export const description = "A JavaScript library and CLI tool for generating plots from mathematical expressions and time series data";

export function getIdentity() {
  return { name, version, description };
}

export function parseExpression(expression) {
  // Remove y= prefix if present
  const expr = expression.replace(/^y\s*=\s*/, '');
  
  // Create a safe evaluation function using Math object
  try {
    const func = new Function('x', 'Math', `return ${expr}`);
    return (x) => func(x, Math);
  } catch (error) {
    throw new Error(`Invalid expression: ${expression}`);
  }
}

export function parseRange(range) {
  const parts = range.split(':');
  if (parts.length !== 3) {
    throw new Error('Range must be in format start:step:end');
  }
  
  const [start, step, end] = parts.map(Number);
  if (isNaN(start) || isNaN(step) || isNaN(end)) {
    throw new Error('Range values must be numbers');
  }
  
  return { start, step, end };
}

export function evaluateRange(func, range) {
  const { start, step, end } = typeof range === 'string' ? parseRange(range) : range;
  const points = [];
  
  for (let x = start; x <= end; x += step) {
    points.push({ x, y: func(x) });
  }
  
  return points;
}

export async function loadCSV(filePath) {
  if (!isNode) {
    throw new Error('CSV loading only available in Node.js environment');
  }
  
  if (!existsSync(filePath)) {
    throw new Error(`CSV file not found: ${filePath}`);
  }
  
  const content = await readFile(filePath, 'utf8');
  const lines = content.trim().split('\n');
  
  if (lines.length < 2) {
    throw new Error('CSV must have at least a header and one data row');
  }
  
  const header = lines[0].split(',').map(h => h.trim());
  if (!header.includes('time') || !header.includes('value')) {
    throw new Error('CSV must have "time" and "value" columns');
  }
  
  const timeIndex = header.indexOf('time');
  const valueIndex = header.indexOf('value');
  
  const points = [];
  for (let i = 1; i < lines.length; i++) {
    const values = lines[i].split(',').map(v => v.trim());
    const time = Number(values[timeIndex]);
    const value = Number(values[valueIndex]);
    
    if (!isNaN(time) && !isNaN(value)) {
      points.push({ x: time, y: value });
    }
  }
  
  return points;
}

export function renderSVG(points, options = {}) {
  const { width = 800, height = 600, margin = 50 } = options;
  
  if (!points || points.length === 0) {
    throw new Error('No data points to render');
  }
  
  // Find data bounds
  const xValues = points.map(p => p.x);
  const yValues = points.map(p => p.y);
  const xMin = Math.min(...xValues);
  const xMax = Math.max(...xValues);
  const yMin = Math.min(...yValues);
  const yMax = Math.max(...yValues);
  
  // Scale points to SVG coordinates
  const plotWidth = width - 2 * margin;
  const plotHeight = height - 2 * margin;
  
  const scaleX = plotWidth / (xMax - xMin);
  const scaleY = plotHeight / (yMax - yMin);
  
  const scaledPoints = points.map(p => {
    const x = margin + (p.x - xMin) * scaleX;
    const y = height - margin - (p.y - yMin) * scaleY;
    return `${x},${y}`;
  }).join(' ');
  
  return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}">
  <rect width="${width}" height="${height}" fill="white" stroke="black" stroke-width="1"/>
  <polyline points="${scaledPoints}" fill="none" stroke="blue" stroke-width="2"/>
</svg>`;
}

export async function renderPNG(points, options = {}) {
  if (!isNode) {
    throw new Error('PNG rendering only available in Node.js environment');
  }
  
  const { createCanvas } = await import('canvas');
  const { width = 800, height = 600, margin = 50 } = options;
  
  if (!points || points.length === 0) {
    throw new Error('No data points to render');
  }
  
  const canvas = createCanvas(width, height);
  const ctx = canvas.getContext('2d');
  
  // Clear background
  ctx.fillStyle = 'white';
  ctx.fillRect(0, 0, width, height);
  
  // Draw border
  ctx.strokeStyle = 'black';
  ctx.lineWidth = 1;
  ctx.strokeRect(0, 0, width, height);
  
  // Find data bounds
  const xValues = points.map(p => p.x);
  const yValues = points.map(p => p.y);
  const xMin = Math.min(...xValues);
  const xMax = Math.max(...xValues);
  const yMin = Math.min(...yValues);
  const yMax = Math.max(...yValues);
  
  // Scale and draw polyline
  const plotWidth = width - 2 * margin;
  const plotHeight = height - 2 * margin;
  
  const scaleX = plotWidth / (xMax - xMin);
  const scaleY = plotHeight / (yMax - yMin);
  
  ctx.strokeStyle = 'blue';
  ctx.lineWidth = 2;
  ctx.beginPath();
  
  points.forEach((p, i) => {
    const x = margin + (p.x - xMin) * scaleX;
    const y = height - margin - (p.y - yMin) * scaleY;
    
    if (i === 0) {
      ctx.moveTo(x, y);
    } else {
      ctx.lineTo(x, y);
    }
  });
  
  ctx.stroke();
  
  return canvas.toBuffer('image/png');
}

export async function savePlot(points, filePath, options = {}) {
  if (!isNode) {
    throw new Error('File saving only available in Node.js environment');
  }
  
  const ext = filePath.toLowerCase().split('.').pop();
  
  if (ext === 'svg') {
    const svg = renderSVG(points, options);
    await writeFile(filePath, svg, 'utf8');
  } else if (ext === 'png') {
    const png = await renderPNG(points, options);
    await writeFile(filePath, png);
  } else {
    throw new Error('Unsupported file format. Use .svg or .png');
  }
}

